const upd = $input.first().json;
let chatId, text;

if (upd.callback_query) {
  chatId = upd.callback_query.message.chat.id;
  text = upd.callback_query.data;
} else if (upd.message) {
  chatId = upd.message.chat.id;
  text = (upd.message.text || '').trim();
} else {
  return [];
}

return [{ json: { sessionId: String(chatId), chatId: String(chatId), text } }];
